import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.CMAFtOGK.js";const y=JSON.parse('{"title":"语法考点精讲","description":"公共英语 · 语法考点精讲","frontmatter":{"title":"语法考点精讲","description":"公共英语 · 语法考点精讲","category":"english-note"},"headers":[],"relativePath":"posts/english/notes/grammar.md","filePath":"posts/english/notes/grammar.md","lastUpdated":1784747786000}'),n={name:"posts/english/notes/grammar.md"};function s(r,t,o,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="📐-语法考点精讲" tabindex="-1">📐 语法考点精讲 <a class="header-anchor" href="#📐-语法考点精讲" aria-label="Permalink to &quot;📐 语法考点精讲&quot;">​</a></h1><blockquote><p>专升本英语核心语法 | 时态/语态/从句/虚拟语气/非谓语</p></blockquote><hr><h2 id="一、动词时态-🔥-必考" tabindex="-1">一、动词时态（🔥 必考） <a class="header-anchor" href="#一、动词时态-🔥-必考" aria-label="Permalink to &quot;一、动词时态（🔥 必考）&quot;">​</a></h2><h3 id="⏰-三大核心时态" tabindex="-1">⏰ 三大核心时态 <a class="header-anchor" href="#⏰-三大核心时态" aria-label="Permalink to &quot;⏰ 三大核心时态&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时态</th><th style="text-align:left;">结构</th><th style="text-align:left;">用法</th><th style="text-align:left;">标志词</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>一般现在时</strong></td><td style="text-align:left;">do/does</td><td style="text-align:left;">习惯、真理、状态</td><td style="text-align:left;">always, usually, often, every...</td></tr><tr><td style="text-align:left;"><strong>一般过去时</strong></td><td style="text-align:left;">did</td><td style="text-align:left;">过去发生的动作</td><td style="text-align:left;">yesterday, last..., ago, in 2020</td></tr><tr><td style="text-align:left;"><strong>一般将来时</strong></td><td style="text-align:left;">will do</td><td style="text-align:left;">将要发生的动作</td><td style="text-align:left;">tomorrow, next..., soon, in the future</td></tr></tbody></table><h3 id="🔥-完形-语法填空最高频时态" tabindex="-1">🔥 完形/语法填空最高频时态 <a class="header-anchor" href="#🔥-完形-语法填空最高频时态" aria-label="Permalink to &quot;🔥 完形/语法填空最高频时态&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时态</th><th style="text-align:left;">结构</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>现在完成时</strong></td><td style="text-align:left;">have/has done</td><td style="text-align:left;">过去发生对现在有影响 / 持续到现在</td></tr><tr><td style="text-align:left;"><strong>过去完成时</strong></td><td style="text-align:left;">had done</td><td style="text-align:left;">过去的过去（站在过去看更早）</td></tr><tr><td style="text-align:left;"><strong>现在进行时</strong></td><td style="text-align:left;">am/is/are doing</td><td style="text-align:left;">此刻正在发生</td></tr><tr><td style="text-align:left;"><strong>过去进行时</strong></td><td style="text-align:left;">was/were doing</td><td style="text-align:left;">过去某时刻正在发生</td></tr><tr><td style="text-align:left;"><strong>现在完成进行时</strong></td><td style="text-align:left;">have/has been doing</td><td style="text-align:left;">从过去到现在一直持续</td></tr></tbody></table><blockquote><p><strong>真题规律：</strong> 80%的时态题在 <strong>一般过去时</strong>、<strong>现在完成时</strong>、<strong>一般现在时</strong> 三者之间选择</p></blockquote><h3 id="📌-现在完成时-vs-一般过去时-必考辨析" tabindex="-1">📌 现在完成时 vs 一般过去时（必考辨析） <a class="header-anchor" href="#📌-现在完成时-vs-一般过去时-必考辨析" aria-label="Permalink to &quot;📌 现在完成时 vs 一般过去时（必考辨析）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">现在完成时</th><th style="text-align:left;">一般过去时</th></tr></thead><tbody><tr><td style="text-align:left;">时间焦点</td><td style="text-align:left;"><strong>现在</strong>（关注结果）</td><td style="text-align:left;"><strong>过去</strong>（关注动作本身）</td></tr><tr><td style="text-align:left;">能否用具体时间</td><td style="text-align:left;">❌ 不能</td><td style="text-align:left;">✅ 可以</td></tr><tr><td style="text-align:left;">例句</td><td style="text-align:left;">I have seen the movie.（现在知道内容）</td><td style="text-align:left;">I saw the movie last night.</td></tr></tbody></table><p><strong>标志词区分：</strong></p><ul><li>完成时：already, yet, ever, never, just, recently, so far, since, for</li><li>过去时：yesterday, last..., ...ago, in 2020, when I was...</li></ul><hr><h2 id="二、被动语态" tabindex="-1">二、被动语态 <a class="header-anchor" href="#二、被动语态" aria-label="Permalink to &quot;二、被动语态&quot;">​</a></h2><h3 id="结构公式" tabindex="-1">结构公式 <a class="header-anchor" href="#结构公式" aria-label="Permalink to &quot;结构公式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>be + done (过去分词)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="各时态被动语态" tabindex="-1">各时态被动语态 <a class="header-anchor" href="#各时态被动语态" aria-label="Permalink to &quot;各时态被动语态&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时态</th><th style="text-align:left;">被动结构</th></tr></thead><tbody><tr><td style="text-align:left;">一般现在时</td><td style="text-align:left;">am/is/are + done</td></tr><tr><td style="text-align:left;">一般过去时</td><td style="text-align:left;">was/were + done</td></tr><tr><td style="text-align:left;">一般将来时</td><td style="text-align:left;">will be + done</td></tr><tr><td style="text-align:left;">现在完成时</td><td style="text-align:left;">have/has been + done</td></tr><tr><td style="text-align:left;">过去完成时</td><td style="text-align:left;">had been + done</td></tr><tr><td style="text-align:left;">情态动词</td><td style="text-align:left;">can/must/may + be + done</td></tr></tbody></table><h3 id="易错点" tabindex="-1">易错点 <a class="header-anchor" href="#易错点" aria-label="Permalink to &quot;易错点&quot;">​</a></h3><ul><li><strong>主动表被动：</strong> need/want/require + doing = need to be done <ul><li><em>The car needs <strong>washing</strong>.</em> = The car needs <strong>to be washed</strong>.</li></ul></li><li><strong>感官动词：</strong> look, sound, feel, taste, smell + 形容词（主动表被动） <ul><li><em>The flower <strong>smells good</strong>.</em></li></ul></li></ul><hr><h2 id="三、三大从句-🔥🔥-必考" tabindex="-1">三、三大从句（🔥🔥 必考） <a class="header-anchor" href="#三、三大从句-🔥🔥-必考" aria-label="Permalink to &quot;三、三大从句（🔥🔥 必考）&quot;">​</a></h2><h3 id="_1️⃣-定语从句" tabindex="-1">1️⃣ 定语从句 <a class="header-anchor" href="#_1️⃣-定语从句" aria-label="Permalink to &quot;1️⃣ 定语从句&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">先行词</th><th style="text-align:left;">人</th><th style="text-align:left;">物</th><th style="text-align:left;">人+物/所有格</th></tr></thead><tbody><tr><td style="text-align:left;">主格</td><td style="text-align:left;">who/that</td><td style="text-align:left;">which/that</td><td style="text-align:left;">that</td></tr><tr><td style="text-align:left;">宾格</td><td style="text-align:left;">who(m)/that</td><td style="text-align:left;">which/that</td><td style="text-align:left;">that</td></tr><tr><td style="text-align:left;">所有格</td><td style="text-align:left;">whose</td><td style="text-align:left;">whose/of which</td><td style="text-align:left;">whose</td></tr></tbody></table><p><strong>非限制性定语从句：</strong> 不能用 that，用 which / who</p><blockquote><p><em>The book, <strong>which</strong> I bought yesterday, is very interesting.</em></p></blockquote><h3 id="_2️⃣-名词性从句" tabindex="-1">2️⃣ 名词性从句 <a class="header-anchor" href="#_2️⃣-名词性从句" aria-label="Permalink to &quot;2️⃣ 名词性从句&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">引导词</th><th style="text-align:left;">例句</th></tr></thead><tbody><tr><td style="text-align:left;">主语从句</td><td style="text-align:left;">that / whether / what</td><td style="text-align:left;"><strong>What</strong> he said is true.</td></tr><tr><td style="text-align:left;">宾语从句</td><td style="text-align:left;">that / if/whether / wh-</td><td style="text-align:left;">I think <strong>that</strong> he is right.</td></tr><tr><td style="text-align:left;">表语从句</td><td style="text-align:left;">that / whether / wh-</td><td style="text-align:left;">The question is <strong>whether</strong> we should go.</td></tr><tr><td style="text-align:left;">同位语从句</td><td style="text-align:left;">that</td><td style="text-align:left;">The news <strong>that</strong> he won surprised us.</td></tr></tbody></table><h3 id="_3️⃣-状语从句" tabindex="-1">3️⃣ 状语从句 <a class="header-anchor" href="#_3️⃣-状语从句" aria-label="Permalink to &quot;3️⃣ 状语从句&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">引导词</th></tr></thead><tbody><tr><td style="text-align:left;">时间</td><td style="text-align:left;">when, while, as, before, after, until, as soon as</td></tr><tr><td style="text-align:left;">条件</td><td style="text-align:left;">if, unless, as long as, provided that</td></tr><tr><td style="text-align:left;">原因</td><td style="text-align:left;">because, since, as, now that</td></tr><tr><td style="text-align:left;">让步</td><td style="text-align:left;">although, though, even though, while, no matter...</td></tr><tr><td style="text-align:left;">目的</td><td style="text-align:left;">so that, in order that</td></tr><tr><td style="text-align:left;">结果</td><td style="text-align:left;">so...that, such...that</td></tr></tbody></table><hr><h2 id="四、虚拟语气-🔥-必考" tabindex="-1">四、虚拟语气（🔥 必考） <a class="header-anchor" href="#四、虚拟语气-🔥-必考" aria-label="Permalink to &quot;四、虚拟语气（🔥 必考）&quot;">​</a></h2><h3 id="三类条件句对比" tabindex="-1">三类条件句对比 <a class="header-anchor" href="#三类条件句对比" aria-label="Permalink to &quot;三类条件句对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">if从句</th><th style="text-align:left;">主句</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>与现在相反</strong></td><td style="text-align:left;"><strong>did/were</strong></td><td style="text-align:left;"><strong>would/could/might + do</strong></td></tr><tr><td style="text-align:left;"><strong>与过去相反</strong></td><td style="text-align:left;"><strong>had done</strong></td><td style="text-align:left;"><strong>would/could/might + have done</strong></td></tr><tr><td style="text-align:left;"><strong>与将来相反</strong></td><td style="text-align:left;"><strong>should do / were to do</strong></td><td style="text-align:left;"><strong>would/could/might + do</strong></td></tr></tbody></table><blockquote><p><strong>专升本规律：</strong> 80%的虚拟语气题只考前两种（与现在/过去相反）</p></blockquote><h3 id="其他虚拟语气考点" tabindex="-1">其他虚拟语气考点 <a class="header-anchor" href="#其他虚拟语气考点" aria-label="Permalink to &quot;其他虚拟语气考点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">考点</th><th style="text-align:left;">结构</th><th style="text-align:left;">例句</th></tr></thead><tbody><tr><td style="text-align:left;">建议/命令/要求</td><td style="text-align:left;"><strong>should do</strong>（should可省）</td><td style="text-align:left;">He suggested that she (should) go.</td></tr><tr><td style="text-align:left;">wish后</td><td style="text-align:left;">时态退一格</td><td style="text-align:left;">I wish I <strong>were</strong> a bird.</td></tr><tr><td style="text-align:left;">as if/though</td><td style="text-align:left;">时态退一格</td><td style="text-align:left;">He talks as if he <strong>knew</strong> everything.</td></tr><tr><td style="text-align:left;">It&#39;s time that...</td><td style="text-align:left;">用过去式</td><td style="text-align:left;">It&#39;s time that we <strong>left</strong>.</td></tr><tr><td style="text-align:left;">would rather that...</td><td style="text-align:left;">用过去式</td><td style="text-align:left;">I&#39;d rather you <strong>came</strong> tomorrow.</td></tr></tbody></table><p><strong>动词清单（接 that 虚拟）：</strong> suggest, advise, propose, recommend, insist, order, command, require, request, demand</p><hr><h2 id="五、非谓语动词-🔥🔥-必考" tabindex="-1">五、非谓语动词（🔥🔥 必考） <a class="header-anchor" href="#五、非谓语动词-🔥🔥-必考" aria-label="Permalink to &quot;五、非谓语动词（🔥🔥 必考）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">形式</th><th style="text-align:left;">意义</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>to do</strong></td><td style="text-align:left;">目的、将来</td><td style="text-align:left;">不定式：表示目的/主动/将来</td></tr><tr><td style="text-align:left;"><strong>doing</strong></td><td style="text-align:left;">主动、进行</td><td style="text-align:left;">现在分词/动名词</td></tr><tr><td style="text-align:left;"><strong>done</strong></td><td style="text-align:left;">被动、完成</td><td style="text-align:left;">过去分词表示被动/完成</td></tr></tbody></table><h3 id="常考固定搭配" tabindex="-1">常考固定搭配 <a class="header-anchor" href="#常考固定搭配" aria-label="Permalink to &quot;常考固定搭配&quot;">​</a></h3><p><strong>只接 to do 的动词：</strong></p><blockquote><p>want, hope, wish, expect, decide, plan, refuse, promise, afford, agree</p></blockquote><p><strong>只接 doing 的动词：</strong></p><blockquote><p>enjoy, finish, avoid, consider, practice, suggest, mind, keep, imagine</p></blockquote><p><strong>既接 to do 又接 doing 意义不同：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">动词</th><th style="text-align:left;">to do</th><th style="text-align:left;">doing</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>remember</strong></td><td style="text-align:left;">记得要去做</td><td style="text-align:left;">记得做过</td></tr><tr><td style="text-align:left;"><strong>forget</strong></td><td style="text-align:left;">忘记要去做</td><td style="text-align:left;">忘记做过</td></tr><tr><td style="text-align:left;"><strong>stop</strong></td><td style="text-align:left;">停下来去做</td><td style="text-align:left;">停止做</td></tr><tr><td style="text-align:left;"><strong>try</strong></td><td style="text-align:left;">努力去做</td><td style="text-align:left;">尝试做</td></tr><tr><td style="text-align:left;"><strong>regret</strong></td><td style="text-align:left;">遗憾要去做</td><td style="text-align:left;">后悔做过</td></tr></tbody></table><hr><h2 id="六、语法填空解题技巧" tabindex="-1">六、语法填空解题技巧 <a class="header-anchor" href="#六、语法填空解题技巧" aria-label="Permalink to &quot;六、语法填空解题技巧&quot;">​</a></h2><h3 id="纯填空-无提示词" tabindex="-1">纯填空（无提示词） <a class="header-anchor" href="#纯填空-无提示词" aria-label="Permalink to &quot;纯填空（无提示词）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">空格位置</th><th style="text-align:left;">可能填的词</th></tr></thead><tbody><tr><td style="text-align:left;">名词前</td><td style="text-align:left;">冠词(a/an/the)、限定词、介词</td></tr><tr><td style="text-align:left;">动词前</td><td style="text-align:left;">情态动词、助动词</td></tr><tr><td style="text-align:left;">两句之间</td><td style="text-align:left;">连词(and, but, or, when, because...)</td></tr><tr><td style="text-align:left;">句中</td><td style="text-align:left;">关系词(who, which, that, where...)</td></tr></tbody></table><h3 id="有提示词" tabindex="-1">有提示词 <a class="header-anchor" href="#有提示词" aria-label="Permalink to &quot;有提示词&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">提示词词性</th><th style="text-align:left;">可能变形成</th></tr></thead><tbody><tr><td style="text-align:left;">动词</td><td style="text-align:left;">时态、语态、非谓语（to do/doing/done）</td></tr><tr><td style="text-align:left;">形容词</td><td style="text-align:left;">副词(-ly)、比较级/最高级</td></tr><tr><td style="text-align:left;">名词</td><td style="text-align:left;">复数、词性转换（→形容词）</td></tr></tbody></table><hr><h2 id="秒杀口诀" tabindex="-1">秒杀口诀 <a class="header-anchor" href="#秒杀口诀" aria-label="Permalink to &quot;秒杀口诀&quot;">​</a></h2><blockquote><p><strong>时态看标志词，完成时找since/for</strong><strong>被动公式be+done，主动表被动要记牢</strong><strong>定语从句找先行，虚拟后退一个时</strong><strong>非谓语三选一，to do目的doing主动done被动</strong></p></blockquote><p>[VOICE: 语法重点抓三大从句、虚拟语气、非谓语动词，这三个板块占语法考题的七成以上，先把它们吃透！]</p>',59)])])}const x=e(n,[["render",s]]);export{y as __pageData,x as default};
